import React, { useState, useEffect } from 'react';

function Login({ onLogin }) {
  const [view, setView] = useState('landing'); 
  const [index, setIndex] = useState(0);

  const images = [
    "https://images.unsplash.com/photo-1500937386664-56d1dfef3854?q=80&w=1000", // Farm field
    "https://images.unsplash.com/photo-1615485290382-441e4d019cb5?q=80&w=1000", // Fresh veggies
    "https://images.unsplash.com/photo-1592419044706-39796d40f98c?q=80&w=1000"  // Market
  ];

  useEffect(() => {
    const timer = setInterval(() => {
      setIndex((prev) => (prev < images.length - 1 ? prev + 1 : 0));
    }, 4000);
    return () => clearInterval(timer);
  }, [images.length]);

  return (
    <div className="container-fluid min-vh-100 d-flex align-items-center justify-content-center p-3 p-md-5">
      <div className="row w-100 g-0 shadow-lg" style={{ borderRadius: '30px', overflow: 'hidden', backgroundColor: 'white' }}>

        {/* LEFT PANEL: The Visual Experience */}
        <div className="col-lg-7 d-none d-lg-block p-0 position-relative">
          <div className="slider-container">
            <div className="slider-inner" style={{ transform: `translateX(-${index * 100}%)` }}>
              {images.map((img, i) => (
                <img key={i} src={img} className="slider-img" alt="Farm" />
              ))}
            </div>
            <div className="position-absolute bottom-0 start-0 p-5 text-white" style={{ background: 'linear-gradient(transparent, rgba(0,0,0,0.7))', width: '100%' }}>
              <h1 className="display-4 fw-bold">Online Farm Portal</h1>
              <p className="lead">Join the next generation of AI-powered agriculture.</p>
            </div>
          </div>
        </div>

        {/* RIGHT PANEL: Interactive Forms */}
        <div className="col-lg-5 p-4 p-md-5 d-flex flex-column justify-content-center">
          <div className="text-center mb-5">
            <h2 className="fw-bold" style={{ color: '#46B951' }}>Agri-AI Platform</h2>
            <p className="text-muted">Smart Farming, Better Yields</p>
          </div>

          {view === 'landing' && (
            <div className="animate__animated animate__fadeIn">
              <button className="agri-btn-primary w-100 mb-3 shadow" onClick={() => setView('login')}>Login to Account</button>
              <div className="text-center my-3 text-muted">⎯⎯⎯⎯ New to the Farm? ⎯⎯⎯⎯</div>
              <div className="row g-2">
                <div className="col-6">
                  <button className="btn btn-outline-success w-100 py-3 rounded-4" onClick={() => setView('signup-buyer')}>Join as Buyer</button>
                </div>
                <div className="col-6">
                  <button className="btn btn-outline-dark w-100 py-3 rounded-4" onClick={() => setView('signup-seller')}>Join as Seller</button>
                </div>
              </div>
            </div>
          )}

          {view === 'login' && (
            <div className="animate__animated animate__fadeIn">
              <h4 className="mb-4 fw-bold">Login</h4>
              <input type="text" className="form-control agri-input" placeholder="Email or Mobile Number" />
              <input type="password" className="form-control agri-input" placeholder="Password" />
              <button className="agri-btn-primary w-100 mt-2" onClick={() => onLogin({role: 'buyer'})}>Login Now</button>
              <button className="btn btn-link w-100 mt-3 text-decoration-none text-success" onClick={() => setView('landing')}>← Back to selection</button>
            </div>
          )}

          {/* SIGNUP FORM (Seller/Buyer) */}
          {(view === 'signup-buyer' || view === 'signup-seller') && (
            <div className="animate__animated animate__fadeIn" style={{ maxHeight: '70vh', overflowY: 'auto', paddingRight: '10px' }}>
              <h4 className="mb-3 fw-bold">{view.split('-')[1].toUpperCase()} Registration</h4>
              <input type="text" className="form-control agri-input" placeholder="Full Name" />
              <input type="text" className="form-control agri-input" placeholder="Mobile Number" />
              <input type="text" className="form-control agri-input" placeholder="Location" />

              {view === 'signup-seller' && (
                <>
                  <input type="text" className="form-control agri-input" placeholder="Aadhar / PAN Card Number" />
                  <div className="mb-3">
                    <label className="small text-muted mb-1">Upload Income Proof</label>
                    <input type="file" className="form-control rounded-3" />
                  </div>
                </>
              )}

              <input type="text" className="form-control agri-input" placeholder="Your Favorite Fruits/Veggies (Optional)" />

              <button className="agri-btn-primary w-100" onClick={() => onLogin({role: view.split('-')[1]})}>Complete Registration</button>
              <button className="btn btn-link w-100 mt-2 text-decoration-none text-muted" onClick={() => setView('landing')}>Cancel</button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

export default Login;
